+/// One layer of a DIT butterfly network where all blocks share the same twiddle factor.
+///
+/// Used in `first_half_general` for layer 0 of the coset DFT. At layer 0, `half_block_size = 1`,
+/// so each block of 2 rows consumes exactly 1 twiddle. Since `dit_layer` clones the iterator
+/// from position 0 for each block, every block uses the same `twiddles[layer_rev][0]`.
+///
+/// This function pre-broadcasts the scalar twiddle into a packed field once, outside all inner
+/// loops, then applies it to every consecutive row-pair in the submatrix. This avoids the
+/// per-block clone + per-row-pair broadcast that `dit_layer` would do, saving ~(num_blocks - 1)
+/// broadcasts across the submatrix for each parallel chunk.
+///
+/// Correctness: Identical to calling `dit_layer` with `layer=0` when all blocks share the
+/// same twiddle (i.e., `twiddles[layer_rev][0]` is the only twiddle consumed per block).
+fn dit_layer_uniform_twiddle<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    twiddle: F,
+    backwards: bool,
+) {
+    // layer=0 means half_block_size=1, block_size=2.
+    let width = submat.width();
+    debug_assert!(submat.height() >= 2);
+
+    // Pre-broadcast the scalar twiddle into a packed field once, outside all loops.
+    // This avoids re-broadcasting the same scalar for every row-pair in the submatrix.
+    let twiddle_packed = F::Packing::from(twiddle);
+
+    let process_block = |block: &mut [F]| {
+        // Each block is exactly 2 rows: lo = block[0..width], hi = block[width..2*width]
+        let (lo, hi) = block.split_at_mut(width);
+
+        // Use packed arithmetic directly with the pre-broadcast twiddle_packed.
+        let (lo_shorts, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+        let (hi_shorts, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+        for (x_lo, x_hi) in lo_shorts.iter_mut().zip(hi_shorts.iter_mut()) {
+            let x_hi_twiddle = *x_hi * twiddle_packed;
+            let new_lo = *x_lo + x_hi_twiddle;
+            *x_hi = *x_lo - x_hi_twiddle;
+            *x_lo = new_lo;
+        }
+        for (x_lo, x_hi) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+            let x_hi_twiddle = *x_hi * twiddle;
+            let new_lo = *x_lo + x_hi_twiddle;
+            *x_hi = *x_lo - x_hi_twiddle;
+            *x_lo = new_lo;
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(2 * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
