+        }
+    }
+
+    #[test]
+    fn dif_zeros_apply_to_rows_matches_scalar(seed: u64, w in 1usize..=33, twiddle in arb_field_elem()) {
+        let mut rng = SmallRng::seed_from_u64(seed);
