+        let mut dst1: Vec<MaybeUninit<F>> = vec![MaybeUninit::uninit(); w];
+        let mut dst2: Vec<MaybeUninit<F>> = vec![MaybeUninit::uninit(); w];
+        TwiddleFreeButterfly.apply_to_rows_oop(&row1, &mut dst1, &row2, &mut dst2);
