+#[test]
+fn dft_width_1_matches_naive() {
+    // Width 1 means a single polynomial (not a batch).
+    // This exercises the degenerate-width code path in every layer.
+    for log_h in 0..=8 {
+        let h = 1 << log_h;
+        let mat = rand_matrix(42, h, 1);
