+/// One layer of a DIT butterfly network where all blocks share the same single twiddle factor.
+///
+/// This is used in `first_half_general` for layer 0, where `half_block_size=1` means
+/// each block is exactly 2 rows and uses exactly one twiddle. Since all blocks within a
+/// parallel chunk use the same twiddle `twiddles[layer_rev][0]`, we pre-broadcast it as
+/// a packed field once, avoiding iterator cloning per block.
+///
+/// Correctness: For layer=0, `half_block_size=1` and each block clones the twiddle
+/// iterator from position 0, consuming only `twiddles[layer_rev][0]`. All blocks in the
+/// same parallel chunk see the same value. Using it directly is equivalent.
+#[inline]
+fn dit_layer_uniform_twiddle<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    twiddle: F,
+    backwards: bool,
+) {
+    // layer=0 means half_block_size=1, block_size=2.
+    let width = submat.width();
+    debug_assert!(submat.height() >= 2);
+
+    // Pre-broadcast the twiddle factor into a packed field once for all blocks.
+    let twiddle_packed = F::Packing::from(twiddle);
+
+    let process_block = |block: &mut [F]| {
+        // Each block is exactly 2 rows: lo = block[0..width], hi = block[width..2*width]
+        let (lo, hi) = block.split_at_mut(width);
+        // Process packed chunks, reusing the pre-broadcast twiddle.
+        let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+        let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+        for (x1, x2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+            let x2_twiddle = *x2 * twiddle_packed;
+            let new_x1 = *x1 + x2_twiddle;
+            *x2 = *x1 - x2_twiddle;
+            *x1 = new_x1;
+        }
+        for (x1, x2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+            let x2_twiddle = *x2 * twiddle;
+            let new_x1 = *x1 + x2_twiddle;
+            *x2 = *x1 - x2_twiddle;
+            *x1 = new_x1;
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(2 * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
