+/// One layer of a DIT butterfly network where all blocks share the same single twiddle factor.
+///
+/// This is used for layer 0 in `first_half_general` (coset DFT), where `half_block_size=1`
+/// means each block of 2 rows uses only one twiddle factor — and since the iterator is cloned
+/// fresh per block and only one element is consumed, all blocks use `twiddles[layer_rev][0]`.
+///
+/// By accepting the twiddle as a scalar directly and pre-broadcasting it once as a packed field,
+/// we avoid the iterator clone and broadcast overhead in the per-block hot path.
+fn dit_layer_single_twiddle<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    twiddle: F,
+    backwards: bool,
+) {
+    // layer=0 means half_block_size=1, block_size=2.
+    let width = submat.width();
+    debug_assert!(submat.height() >= 2);
+
+    // Pre-broadcast the twiddle factor as a packed field once for the entire chunk.
+    let twiddle_packed = F::Packing::from(twiddle);
+
+    let process_block = |block: &mut [F]| {
+        let (lo, hi) = block.split_at_mut(width);
+        // Use packed operations directly, pre-broadcasting twiddle once.
+        let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+        let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+        for (x1, x2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+            let x2t = *x2 * twiddle_packed;
+            let new_x1 = *x1 + x2t;
+            *x2 = *x1 - x2t;
+            *x1 = new_x1;
+        }
+        for (x1, x2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+            let x2t = *x2 * twiddle;
+            let new_x1 = *x1 + x2t;
+            *x2 = *x1 - x2t;
+            *x1 = new_x1;
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(2 * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
