+/// One layer of a DIT butterfly network, using pre-broadcast packed twiddles.
+///
+/// The `scalar_twiddles` and `packed_twiddles` slices must have length `half_block_size = 1 << layer`,
+/// with `packed_twiddles[i] = F::Packing::from(scalar_twiddles[i])` (pre-computed by the caller).
+///
+/// All blocks at a given layer share the same twiddle set (each block starts from index 0),
+/// so broadcasting is done once externally rather than once per block inside `DitButterfly::apply_to_rows`.
+/// This eliminates `(num_blocks - 1) * half_block_size` redundant SIMD broadcast instructions
+/// across the layer.
+fn dit_layer_prepacked<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    scalar_twiddles: &[F],
+    packed_twiddles: &[F::Packing],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+    debug_assert_eq!(scalar_twiddles.len(), half_block_size);
+    debug_assert_eq!(packed_twiddles.len(), half_block_size);
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for ((lo, hi), (twiddle_scalar, twiddle_packed)) in lows
+            .chunks_mut(width)
+            .zip(highs.chunks_mut(width))
+            .zip(scalar_twiddles.iter().zip(packed_twiddles.iter()))
+        {
+            let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+            let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+            for (x1, x2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+                let x2_tw = *x2 * *twiddle_packed;
+                let new_x1 = *x1 + x2_tw;
+                *x2 = *x1 - x2_tw;
+                *x1 = new_x1;
+            }
+            // Scalar suffix fallback (typically empty when width is a multiple of packing width).
+            for (x1, x2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+                DitButterfly(*twiddle_scalar).apply_in_place(x1, x2);
+            }
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
