+        let mut rng = SmallRng::seed_from_u64(seed);
+        let mut row1: Vec<F> = (0..w).map(|_| rng.random()).collect();
+        // Second row is all zeros, matching the zero-padded precondition.
+        let mut row2: Vec<F> = vec![F::ZERO; w];
