+/// One layer of a DIT butterfly network where all blocks share the same twiddle factors.
+///
+/// In `first_half_general`, each block within a layer uses the same twiddle factors
+/// (the iterator is cloned from position 0 for each block). This function takes a slice
+/// of twiddles and directly reuses `&twiddles[0..half_block_size]` for every block,
+/// eliminating the per-block iterator clone overhead.
+///
+/// This is equivalent to `dit_layer` with the given twiddle iterator cloned from position 0,
+/// but uses direct slice indexing to avoid iterator clone overhead.
+fn dit_layer_shared_twiddles<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+
+    // All blocks share the same twiddle factors: twiddles[0..half_block_size].
+    let block_twiddles = &twiddles[..half_block_size];
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (lo, hi, twiddle) in izip!(
+            lows.chunks_mut(width),
+            highs.chunks_mut(width),
+            block_twiddles.iter()
+        ) {
+            DitButterfly(*twiddle).apply_to_rows(lo, hi);
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
