+/// avoiding the per-call broadcast that `DitButterfly::apply_to_rows` would otherwise perform.
+#[inline]
+fn dit_layer_single_twiddle<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    width: usize,
+    twiddle: F,
+    backwards: bool,
+) {
+    // Broadcast the scalar twiddle to a packed field once for all blocks in this layer.
+    let twiddle_packed = F::Packing::from(twiddle);
+    let block_elems = 2 * width; // block_size=2 rows, half_block_size=1
