+        for block in submat.values.chunks_mut(block_elems).rev() {
+            let (lo, hi) = block.split_at_mut(width);
+            apply_dit_rows_prepacked(lo, hi, twiddle, twiddle_packed);
+        }
+    } else {
+        for block in submat.values.chunks_mut(block_elems) {
+            let (lo, hi) = block.split_at_mut(width);
+            apply_dit_rows_prepacked(lo, hi, twiddle, twiddle_packed);
+        }
+    }
