+/// - the scalar suffix path uses the original scalar directly.
+#[inline(always)]
+fn apply_dit_rows_prepacked<F: Field>(
+    lo: &mut [F],
+    hi: &mut [F],
+    twiddle: F,
+    twiddle_packed: F::Packing,
+) {
+    let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+    let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+    for (x1, x2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+        let x2t = *x2 * twiddle_packed;
+        let new_x1 = *x1 + x2t;
+        *x2 = *x1 - x2t;
+        *x1 = new_x1;
+    }
+    // Handle any suffix elements that didn't fit into a full pack.
+    for (x1, x2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+        DitButterfly(twiddle).apply_in_place(x1, x2);
+    }
+}
