+/// One layer of a DIT butterfly network, using direct slice indexing for twiddle access.
+///
+/// This is used in `first_half_general` and `first_half_general_oop` for coset DFTs.
+/// Unlike `dit_layer` which takes an iterator and clones it per block, this function
+/// takes a `&[F]` slice and computes the twiddle offset per block directly, avoiding
+/// iterator clone overhead and enabling the compiler to reason about memory access patterns.
+///
+/// Correctness: For layer `l`, `half_block_size = 2^l`. Block `b` (0-indexed) uses
+/// twiddles `[b * half_block_size .. (b+1) * half_block_size]`. Wait — actually in
+/// `first_half_general`, all blocks in a chunk share the SAME twiddles starting from 0,
+/// because the twiddle array for `layer_rev` already contains exactly the twiddles for
+/// this submat's portion. So block `b` within the chunk uses `twiddles[0..half_block_size]`
+/// (the same sub-slice), which is what the iterator clone already did. We use direct slice
+/// indexing `&twiddles[0..half_block_size]` per block to avoid the iterator state entirely.
+fn dit_layer_slice<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+    // Each block uses the first `half_block_size` twiddles (same for all blocks in the chunk).
+    let block_twiddles = &twiddles[..half_block_size];
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (lo, hi, twiddle) in izip!(
+            lows.chunks_mut(width),
+            highs.chunks_mut(width),
+            block_twiddles.iter()
+        ) {
+            DitButterfly(*twiddle).apply_to_rows(lo, hi);
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
