+        x1 in arb_field_elem(), x2 in arb_field_elem(),
+    ) {
+        // Applying the twiddle-free gate twice must recover the original inputs scaled by 2.
+        // Proof: B(B(x_1, x_2)) = B(x_1+x_2, x_1-x_2)
+        //                        = (2*x_1, 2*x_2).
+        let (a, b) = TwiddleFreeButterfly.apply(x1, x2);
