+/// One layer of a DIT butterfly network, using pre-packed twiddle factors.
+///
+/// This variant takes both the scalar twiddles (for suffix/fallback) and pre-packed
+/// twiddles (for the main SIMD loop). The packed twiddles are pre-broadcast once
+/// per layer outside the parallel block loop, eliminating redundant scalar→vector
+/// broadcasts when multiple blocks share the same twiddle values.
+///
+/// All blocks in `first_half_general` at a given layer use the same `twiddles[0..half_block_size]`
+/// slice, so pre-packing them once saves `(num_blocks - 1) * half_block_size` broadcasts.
+#[inline]
+fn dit_layer_prepacked<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+    packed_twiddles: &[F::Packing],
+    backwards: bool,
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+    debug_assert_eq!(packed_twiddles.len(), half_block_size.min(twiddles.len()));
+
+    let process_block = |block: &mut [F]| {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (i, (lo, hi)) in lows
+            .chunks_mut(width)
+            .zip(highs.chunks_mut(width))
+            .enumerate()
+        {
+            // Use the pre-packed twiddle factor for this row-pair index.
+            let twiddle_packed = packed_twiddles[i];
+            let (lo_packed, lo_suffix) = F::Packing::pack_slice_with_suffix_mut(lo);
+            let (hi_packed, hi_suffix) = F::Packing::pack_slice_with_suffix_mut(hi);
+            for (x_1, x_2) in lo_packed.iter_mut().zip(hi_packed.iter_mut()) {
+                let x_2_tw = *x_2 * twiddle_packed;
+                let new_x1 = *x_1 + x_2_tw;
+                *x_2 = *x_1 - x_2_tw;
+                *x_1 = new_x1;
+            }
+            // Handle suffix (elements that don't fill a full packed word).
+            for (x_1, x_2) in lo_suffix.iter_mut().zip(hi_suffix.iter_mut()) {
+                DitButterfly(twiddles[i]).apply_in_place(x_1, x_2);
+            }
+        }
+    };
+
+    let blocks = submat.values.chunks_mut(block_size * width);
+    if backwards {
+        for block in blocks.rev() {
+            process_block(block);
+        }
+    } else {
+        for block in blocks {
+            process_block(block);
+        }
+    }
+}
