+    ) {
+        // Composing DIF after DIT with the same twiddle t gives:
+        //   DIF(DIT(x_1, x_2))
+        //     = DIF(x_1 + x_2*t, x_1 - x_2*t)
+        //     = (2*x_1, 2*x_2*t^2).
+        let (y1, y2) = DitButterfly(twiddle).apply(x1, x2);
