+        // Proof: B(B(x_1, x_2)) = B(x_1+x_2, x_1-x_2)
+        //                        = (2*x_1, 2*x_2).
+        let (a, b) = TwiddleFreeButterfly.apply(x1, x2);
+        let (c, d) = TwiddleFreeButterfly.apply(a, b);
