+proptest! {
+    #[test]
+    fn dit_apply_to_rows_matches_scalar(seed: u64, w in 1usize..=33, twiddle in arb_field_elem()) {
+        // Build two random rows of width `w`.
+        let mut rng = SmallRng::seed_from_u64(seed);
