+            shorts_1[j + 1] = x1b + t2b;
+            shorts_2[j + 1] = x1b - t2b;
+        }
+        if remainder != 0 {
+            let j = pairs * 2;
+            let x_2_twiddle = shorts_2[j] * twiddle_packed;
+            let new_x1 = shorts_1[j] + x_2_twiddle;
+            shorts_2[j] = shorts_1[j] - x_2_twiddle;
+            shorts_1[j] = new_x1;
         }
+
         for (x_1, x_2) in suffix_1.iter_mut().zip(suffix_2.iter_mut()) {
             self.apply_in_place(x_1, x_2);
         }
