+/// One layer of a DIT butterfly network, always processing blocks in forward order.
+///
+/// This is used in `first_half_general` and `first_half_general_oop` where each block
+/// independently clones its twiddle sub-sequence from position 0, making block processing
+/// order irrelevant to correctness. Always going forward avoids the per-layer branch and
+/// gives the CPU prefetcher a consistent sequential access pattern.
+fn dit_layer_forward<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+
+    for block in submat.values.chunks_mut(block_size * width) {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (lo, hi, twiddle) in izip!(
+            lows.chunks_mut(width),
+            highs.chunks_mut(width),
+            twiddles.iter()
+        ) {
+            DitButterfly(*twiddle).apply_to_rows(lo, hi);
+        }
+    }
+}
