+#[test]
+fn idft_constant_vector() {
+    // The inverse of the constant-polynomial property:
+    // if every evaluation is c, the coefficients are [c, 0, 0, ...].
+    let c = F::from_u8(7);
+    for log_h in 0..=6 {
+        let h = 1 << log_h;
+
+        // Evaluation vector: all entries equal to c.
+        let mat = RowMajorMatrix::new(vec![c; h], 1);
