+        let result = Radix2Dit::default().idft_batch(mat);
+
+        // First coefficient is c.
+        assert_eq!(result.values[0], c, "log_h={log_h}");
+        // All higher coefficients are zero.
+        for (i, &v) in result.values.iter().enumerate().skip(1) {
