+/// Build a deterministic random matrix of the given dimensions.
+fn rand_matrix(seed: u64, h: usize, w: usize) -> RowMajorMatrix<F> {
+    let mut rng = SmallRng::seed_from_u64(seed);
+    RowMajorMatrix::<F>::rand(&mut rng, h, w)
+}
