+/// Proptest strategy for the number of extra bits added during a low-degree extension.
+///
+/// Range [1, 3] tests 2x, 4x, and 8x blowup factors.
+fn arb_added_bits() -> impl Strategy<Value = usize> {
+    1usize..=3
+}
