+/// One layer of a DIT butterfly network, using a slice reference for twiddle factors.
+///
+/// Unlike `dit_layer` (which clones a generic iterator), this function takes a `&[F]` slice
+/// directly and always processes blocks in forward order. Since blocks within a layer are
+/// fully independent, forward vs. backward ordering produces identical results.
+///
+/// Using a slice reference (vs. iterator clone) gives the compiler better visibility into the
+/// memory access pattern, enables bounds-check elimination, and removes iterator state overhead.
+#[inline(always)]
+fn dit_layer_slice<F: Field>(
+    submat: &mut RowMajorMatrixViewMut<'_, F>,
+    layer: usize,
+    twiddles: &[F],
+) {
+    let half_block_size = 1 << layer;
+    let block_size = half_block_size * 2;
+    let width = submat.width();
+    debug_assert!(submat.height() >= block_size);
+
+    for block in submat.values.chunks_mut(block_size * width) {
+        let (lows, highs) = block.split_at_mut(half_block_size * width);
+        for (lo, hi, twiddle) in izip!(
+            lows.chunks_mut(width),
+            highs.chunks_mut(width),
+            twiddles.iter()
+        ) {
+            DitButterfly(*twiddle).apply_to_rows(lo, hi);
+        }
+    }
+}
