+    // A constant polynomial p(x) = c evaluates to c everywhere.
+    // In coefficient form that is [c, 0, 0, ...].
+    // Every evaluation DFT[i] = p(g^i) = c.
+    let c = F::from_u8(13);
+    for log_h in 0..=6 {
